sp_widget.client_script:
api.controller = function($scope, $sce, $timeout, $window, snAnalytics) {
    var c = this;
    c.asyncUpdate = function() {
        c.server.update();
    };
    var load_config = c.data.load_config;
    if (load_config === "async")
        setTimeout(c.asyncUpdate);
    c.panelClass = c.data.renderedFromMenuItem ? "parent-container" : "panel-body";
    c.panelWrapper = c.data.renderedFromMenuItem ? "" : "panel panel-default b panel-wrapper";
    c.itemsMargin = c.data.renderedFromMenuItem ? "flex-container menu-item-margin flex-container-cols" : "flex-container flex-container-cols-modal";

    $scope.handleClick = function(item, event) {
        if (event && (event.keyCode === 13 || event.keyCode === 32)) {
            event.preventDefault();
        }
        if (event.type === 'click' || (event.type === 'keydown' && (event.keyCode === 13 || event.keyCode === 32))) {
            if (item.type == 'guided_help') {
                c.server.get({
                    "action": "openGuidedhelp",
                    "guidedHelpId": item.guided_help
                }).then(function(resp) {
                    $timeout(function() {
                        $window.open(resp.data.guidedHelpResponse.url, '_self');
                        dismissModal();
                    }, raiseAppseeEvent(resp.data.guidedHelpResponse));
                });
            } else if (item.url && item.url.length > 0) {
                $window.open(item.url, '_self');
                dismissModal();
            }
        }
    };

    $scope.trustAsHtml = function(string) {
        return $sce.trustAsHtml(string);
    };

    function raiseAppseeEvent(data) {
        if (!data.isNew) {
            return;
        }
        var payload = {};
        payload.name = "Guided Self-service Started";
        payload.data = {};
        payload.data["Guided Self-service"] = data.processName;
        payload.data["User Id"] = data.userId;
        payload.data["Source"] = data.source;
        snAnalytics.addEvent(payload);
    }

    function dismissModal() {
        if (c.data.renderedFromMenuItem) {
            $scope.$parent.$parent.$dismiss();
        }
    }
};

sp_widget.css:
$border-primary: #8790A1 !default;
$border-secondary: #B3B7BC !default;
$border-tertiary: #DADDE2 !default;
$text-primary: #1D2223 !default;
$border-radius-base: 4px !default;
$sp-panel-box-shadow: 0 4px 8px 0 rgba(23, 40, 52, 0.08) !default;
$headings-font-weight: 600 !default;
$sp-space--xs: 8px !default;
$sp-space--md: 12px !default;
$sp-space--lg: 16px !default;
$font-size-base: 16px !default;
$sp-space--xl: 24px !default;


.card-container {
	min-height: 88px;
	display: flex;
	align-items: center;
	max-height: 120px;
  	height: 100%;
}

.parent-container {
	max-height: 70vh;
	overflow-y: scroll;
}

.content-container {
	padding: $sp-space--lg;
	align-items: center;
	display: grid;
  	height: 100%;
}

.icon-container {
	margin-left: $sp-space--lg;
	display: flex;
	align-items: center;
}

img {
	height: 56px;
	width: 56px;
}

.parent-content-container {
	display: flex;
	flex-direction: row;
}

.content-title {
	color: $text-primary;
	font-size: $font-size-base;
	font-weight: $headings-font-weight;
	display: -webkit-box;
	-webkit-box-orient: vertical;
	overflow: hidden;
}

.webkit-clamp-1 {
	-webkit-line-clamp: 1;
}

.webkit-clamp-2 {
	-webkit-line-clamp: 2;
}

.fa-folder-open {
	font-size: 52px;
	color: $text-tertiary;
}

.empty-content-title {
	color: $text-primary;
	font-size: $font-size-h4;
	font-weight: $headings-font-weight;
	margin-top: $sp-space--md;

}

.empty-content {
	font-size: $font-size-base;
	color: $text-secondary;
	font-size: $font-size-base;
	font-weight: 400;
	margin-top: $sp-space--md;
	width: 60%;
}

.empty-section {
	margin-top: 26px;
	margin-bottom: 26px;
}

.link-desc {
	color: $text-primary;
	font-size: $font-size-base;
}

.flex-container {
	display: grid;
	flex-wrap: wrap;
	height: inherit;
	width: inherit;
	row-gap: $sp-space--lg;
	column-gap: $sp-space--lg;
	justify-content: space-between;

}

.flex-container-cols {
  grid-template-columns: repeat(auto-fit, minmax(27rem, 1fr));
}


.flex-container-cols-modal {
  grid-template-columns: repeat(auto-fit, minmax(23.8rem, 1fr));
}

.menu-item-margin {
	margin: 16px;
}

.col {
	border: 1px solid $border-tertiary;
	border-radius: $border-radius-base;
	flex-direction: column;
}

.content {
	-webkit-line-clamp: 2;
	-webkit-box-orient: vertical;
	overflow: hidden;
	margin-top: $sp-space--xs;
  	height: 100%;
  	display: block;
}

.panel-body {
	padding: 24px;
}

a.card-container{
  border-radius: $border-radius-base;
}
.col:hover {
	box-shadow: $sp-panel-box-shadow;
}

@media (max-width: 750px) {
	.col {
		flex-basis: 100%;
	}
}
.link-desc {
  display: -webkit-box;
}
@media (max-width: 430px) {
  .flex-container-cols-modal {
    grid-template-columns: 1fr;
  }
  .flex-container-cols {
    grid-template-columns: 1fr;
  }
}
.skeleton-loader {
  background: rgb(239, 241, 246) no-repeat;
  background-image: linear-gradient(90deg, rgba(255, 255, 255, 0), rgba(255, 255, 255, 0.6), rgba(255, 255, 255, 0));
  border-radius: 4px;
  animation: progress 2s ease-in-out infinite;
}

sp_widget.link:
function link(scope, element, attrs, controller) {
    $(document).ready(function() {
        var staticContent = document.getElementsByClassName('static');

        for (var i = 0; i < staticContent.length; i++) {
            var staticContentRect = staticContent[i].getBoundingClientRect();
            var contentLeft = staticContentRect.left;
            var contentRight = staticContentRect.right;
            var contentTop = staticContentRect.top;
            var contentBottom = staticContentRect.bottom;
            var aTag = staticContent[i].getElementsByTagName("a");
            for (var j = 0; j < aTag.length; j++) {

                var aRect = aTag[j].getBoundingClientRect();
                var aLeft = aRect.left;
                var aRight = aRect.right;
                var aTop = aRect.top;
                var aBottom = aRect.bottom;
                if (!(aLeft >= contentLeft && aRight <= contentRight && aTop >= contentTop && aBottom <= contentBottom))
                    aTag[j].tabIndex = -1;

            }


        }
    });
}

sp_widget.script:
(function() {
    data.loading = true;
    data.renderedFromMenuItem = input && input.renderedFromMenuItem ? true : false;
    data.load_config = data.renderedFromMenuItem === true ? "sync" : (options && options.load_config ? options.load_config : "");
    data.show_title = data.renderedFromMenuItem === true ? false : true;
    if (data.load_config === "async" && !input)
        return;
    data.getSupportItems = [];
    var empty_state = options && (options.show_empty_state === "true" || options.show_empty_state === true);
    data.portal = $sp.getPortalRecord();
    var getSupportUtil = new sn_ex_sp.GetSupportUtil(data.portal.getUniqueValue());
    data.getSupportItems = getSupportUtil.fetchSupportRecords();
    data.showEmptyState = showEmptyState();
    data.loading = false;

    if (input && input.action == 'openGuidedhelp' && input.guidedHelpId) {
        data.pageId = $sp.getParameter('id') ? $sp.getParameter('id') : data.portal.homepage.getDisplayValue();
        data.guidedHelpResponse = new sn_ex_sp.QuickLinkUtil().handleGuidedHelpClick(input.guidedHelpId, data.pageId, "quick_link_from_getsupport");
    }

    function showEmptyState() {
        if (data.getSupportItems.length === 0 && (data.renderedFromMenuItem || empty_state))
            return true;
        return false;
    }

})();
